import os
import secrets
import hashlib
import hmac
import time
from datetime import datetime, timedelta
from flask import Flask, request, jsonify, render_template_string
from flask_sqlalchemy import SQLAlchemy
from werkzeug.security import generate_password_hash, check_password_hash
import pyotp
from functools import wraps

app = Flask(__name__)
app.config['SECRET_KEY'] = os.environ.get('SECRET_KEY', secrets.token_hex(32))
app.config['SQLALCHEMY_DATABASE_URI'] = 'sqlite:///mfa_system.db'
app.config['SQLALCHEMY_TRACK_MODIFICATIONS'] = False

db = SQLAlchemy(app)

# Models
class User(db.Model):
    id = db.Column(db.Integer, primary_key=True)
    email = db.Column(db.String(120), unique=True, nullable=False)
    password_hash = db.Column(db.String(200), nullable=False)
    mfa_enabled = db.Column(db.Boolean, default=False)
    mfa_secret = db.Column(db.String(32), nullable=True)
    created_at = db.Column(db.DateTime, default=datetime.utcnow)

class Session(db.Model):
    id = db.Column(db.Integer, primary_key=True)
    user_id = db.Column(db.Integer, db.ForeignKey('user.id'), nullable=False)
    token = db.Column(db.String(64), unique=True, nullable=False)
    mfa_verified = db.Column(db.Boolean, default=False)
    created_at = db.Column(db.DateTime, default=datetime.utcnow)
    expires_at = db.Column(db.DateTime, nullable=False)

class MFAResetToken(db.Model):
    id = db.Column(db.Integer, primary_key=True)
    user_id = db.Column(db.Integer, db.ForeignKey('user.id'), nullable=False)
    token = db.Column(db.String(64), unique=True, nullable=False)
    used = db.Column(db.Boolean, default=False)
    created_at = db.Column(db.DateTime, default=datetime.utcnow)
    expires_at = db.Column(db.DateTime, nullable=False)
    ip_address = db.Column(db.String(45), nullable=True)

class AuditLog(db.Model):
    id = db.Column(db.Integer, primary_key=True)
    user_id = db.Column(db.Integer, db.ForeignKey('user.id'), nullable=True)
    action = db.Column(db.String(100), nullable=False)
    ip_address = db.Column(db.String(45), nullable=True)
    user_agent = db.Column(db.String(200), nullable=True)
    success = db.Column(db.Boolean, default=True)
    details = db.Column(db.Text, nullable=True)
    created_at = db.Column(db.DateTime, default=datetime.utcnow)

with app.app_context():
    db.create_all()

# Helper functions
def log_audit(user_id, action, success=True, details=None):
    log = AuditLog(
        user_id=user_id,
        action=action,
        ip_address=request.remote_addr,
        user_agent=request.headers.get('User-Agent'),
        success=success,
        details=details
    )
    db.session.add(log)
    db.session.commit()

def send_email(to_email, subject, body):
    # In production, integrate with actual email service (SendGrid, SES, etc.)
    print(f"=== EMAIL ===")
    print(f"To: {to_email}")
    print(f"Subject: {subject}")
    print(f"Body: {body}")
    print(f"=============")
    return True

def generate_secure_token():
    return secrets.token_urlsafe(48)

def require_auth(require_mfa=False):
    def decorator(f):
        @wraps(f)
        def decorated_function(*args, **kwargs):
            token = request.headers.get('Authorization')
            if not token or not token.startswith('Bearer '):
                return jsonify({'error': 'Authentication required'}), 401
            
            token = token.replace('Bearer ', '')
            session = Session.query.filter_by(token=token).first()
            
            if not session or session.expires_at < datetime.utcnow():
                return jsonify({'error': 'Invalid or expired session'}), 401
            
            user = User.query.get(session.user_id)
            if not user:
                return jsonify({'error': 'User not found'}), 401
            
            # Critical: If MFA is enabled for user, session MUST have MFA verified
            if user.mfa_enabled and not session.mfa_verified:
                return jsonify({'error': 'MFA verification required'}), 403
            
            if require_mfa and not session.mfa_verified:
                return jsonify({'error': 'MFA verification required'}), 403
            
            request.current_user = user
            request.current_session = session
            return f(*args, **kwargs)
        return decorated_function
    return decorator

# Routes
@app.route('/register', methods=['POST'])
def register():
    data = request.get_json()
    email = data.get('email')
    password = data.get('password')
    
    if not email or not password:
        return jsonify({'error': 'Email and password required'}), 400
    
    if User.query.filter_by(email=email).first():
        return jsonify({'error': 'Email already registered'}), 400
    
    user = User(
        email=email,
        password_hash=generate_password_hash(password)
    )
    db.session.add(user)
    db.session.commit()
    
    log_audit(user.id, 'USER_REGISTERED')
    
    return jsonify({'message': 'User registered successfully', 'user_id': user.id}), 201

@app.route('/login', methods=['POST'])
def login():
    data = request.get_json()
    email = data.get('email')
    password = data.get('password')
    
    if not email or not password:
        return jsonify({'error': 'Email and password required'}), 400
    
    user = User.query.filter_by(email=email).first()
    
    if not user or not check_password_hash(user.password_hash, password):
        log_audit(None, 'LOGIN_FAILED', success=False, details=f'Email: {email}')
        return jsonify({'error': 'Invalid credentials'}), 401
    
    # Create session with MFA not verified initially
    session_token = generate_secure_token()
    session = Session(
        user_id=user.id,
        token=session_token,
        mfa_verified=False,  # Always start as not verified
        expires_at=datetime.utcnow() + timedelta(hours=24)
    )
    db.session.add(session)
    db.session.commit()
    
    log_audit(user.id, 'LOGIN_PASSWORD_SUCCESS')
    
    response = {
        'token': session_token,
        'mfa_required': user.mfa_enabled
    }
    
    # If MFA is not enabled, mark session as MFA verified
    if not user.mfa_enabled:
        session.mfa_verified = True
        db.session.commit()
        response['mfa_verified'] = True
    else:
        response['mfa_verified'] = False
    
    return jsonify(response), 200

@app.route('/verify-mfa', methods=['POST'])
def verify_mfa():
    token = request.headers.get('Authorization')
    if not token or not token.startswith('Bearer '):
        return jsonify({'error': 'Authentication required'}), 401
    
    token = token.replace('Bearer ', '')
    session = Session.query.filter_by(token=token).first()
    
    if not session or session.expires_at < datetime.utcnow():
        return jsonify({'error': 'Invalid or expired session'}), 401
    
    user = User.query.get(session.user_id)
    if not user:
        return jsonify({'error': 'User not found'}), 401
    
    if not user.mfa_enabled:
        return jsonify({'error': 'MFA not enabled for this user'}), 400
    
    if session.mfa_verified:
        return jsonify({'message': 'MFA already verified'}), 200
    
    data = request.get_json()
    code = data.get('code')
    
    if not code:
        return jsonify({'error': 'MFA code required'}), 400
    
    totp = pyotp.TOTP(user.mfa_secret)
    if not totp.verify(code, valid_window=1):
        log_audit(user.id, 'MFA_VERIFICATION_FAILED', success=False)
        return jsonify({'error': 'Invalid MFA code'}), 401
    
    # Mark session as MFA verified
    session.mfa_verified = True
    db.session.commit()
    
    log_audit(user.id, 'MFA_VERIFICATION_SUCCESS')
    
    return jsonify({'message': 'MFA verified successfully'}), 200

@app.route('/enable-mfa', methods=['POST'])
@require_auth(require_mfa=False)
def enable_mfa():
    user = request.current_user
    
    if user.mfa_enabled:
        return jsonify({'error': 'MFA already enabled'}), 400
    
    # Generate new MFA secret
    secret = pyotp.random_base32()
    totp = pyotp.TOTP(secret)
    
    # Return provisioning URI for QR code generation
    provisioning_uri = totp.provisioning_uri(
        name=user.email,
        issuer_name='MFA System'
    )
    
    # Store secret temporarily (not enabled yet)
    user.mfa_secret = secret
    db.session.commit()
    
    log_audit(user.id, 'MFA_SETUP_INITIATED')
    
    return jsonify({
        'secret': secret,
        'provisioning_uri': provisioning_uri,
        'message': 'Scan QR code and verify with code to enable MFA'
    }), 200

@app.route('/confirm-enable-mfa', methods=['POST'])
@require_auth(require_mfa=False)
def confirm_enable_mfa():
    user = request.current_user
    
    if user.mfa_enabled:
        return jsonify({'error': 'MFA already enabled'}), 400
    
    if not user.mfa_secret:
        return jsonify({'error': 'MFA setup not initiated'}), 400
    
    data = request.get_json()
    code = data.get('code')
    
    if not code:
        return jsonify({'error': 'Verification code required'}), 400
    
    totp = pyotp.TOTP(user.mfa_secret)
    if not totp.verify(code, valid_window=1):
        log_audit(user.id, 'MFA_ENABLE_FAILED', success=False, details='Invalid code')
        return jsonify({'error': 'Invalid verification code'}), 401
    
    # Enable MFA
    user.mfa_enabled = True
    db.session.commit()
    
    # CRITICAL: Invalidate current session to force re-authentication with MFA
    request.current_session.mfa_verified = False
    db.session.commit()
    
    log_audit(user.id, 'MFA_ENABLED')
    
    return jsonify({
        'message': 'MFA enabled successfully. Please log in again with MFA.'
    }), 200

@app.route('/disable-mfa', methods=['POST'])
@require_auth(require_mfa=False)
def disable_mfa():
    user = request.current_user
    
    if not user.mfa_enabled:
        return jsonify({'error': 'MFA not enabled'}), 400
    
    # CRITICAL: Require MFA verification to disable MFA
    if not request.current_session.mfa_verified:
        return jsonify({'error': 'MFA verification required to disable MFA'}), 403
    
    data = request.get_json()
    password = data.get('password')
    code = data.get('code')
    
    if not password or not code:
        return jsonify({'error': 'Password and MFA code required'}), 400
    
    # Verify password
    if not check_password_hash(user.password_hash, password):
        log_audit(user.id, 'MFA_DISABLE_FAILED', success=False, details='Invalid password')
        return jsonify({'error': 'Invalid password'}), 401
    
    # Verify MFA code
    totp = pyotp.TOTP(user.mfa_secret)
    if not totp.verify(code, valid_window=1):
        log_audit(user.id, 'MFA_DISABLE_FAILED', success=False, details='Invalid MFA code')
        return jsonify({'error': 'Invalid MFA code'}), 401
    
    # Disable MFA
    user.mfa_enabled = False
    user.mfa_secret = None
    db.session.commit()
    
    log_audit(user.id, 'MFA_DISABLED')
    
    return jsonify({'message': 'MFA disabled successfully'}), 200

@app.route('/reset-mfa', methods=['POST'])
def reset_mfa():
    data = request.get_json()
    email = data.get('email')
    
    if not email:
        return jsonify({'error': 'Email required'}), 400
    
    user = User.query.filter_by(email=email).first()
    
    # Always return success to prevent email enumeration
    response_message = 'If the email is registered and MFA is enabled, a reset link has been sent.'
    
    if not user:
        log_audit(None, 'MFA_RESET_REQUESTED', success=False, details=f'Unknown email: {email}')
        return jsonify({'message': response_message}), 200
    
    if not user.mfa_enabled:
        log_audit(user.id, 'MFA_RESET_REQUESTED', success=False, details='MFA not enabled')
        return jsonify({'message': response_message}), 200
    
    # Check for recent reset tokens to prevent abuse
    recent_tokens = MFAResetToken.query.filter(
        MFAResetToken.user_id == user.id,
        MFAResetToken.created_at > datetime.utcnow() - timedelta(minutes=15)
    ).count()
    
    if recent_tokens >= 3:
        log_audit(user.id, 'MFA_RESET_RATE_LIMITED', success=False)
        return jsonify({'message': response_message}), 200
    
    # Generate reset token
    reset_token = generate_secure_token()
    mfa_reset = MFAResetToken(
        user_id=user.id,
        token=reset_token,
        expires_at=datetime.utcnow() + timedelta(hours=1),
        ip_address=request.remote_addr
    )
    db.session.add(mfa_reset)
    db.session.commit()
    
    # Send reset email
    reset_link = f"http://localhost:5000/confirm-reset-mfa?token={reset_token}"
    email_body = f"""
    You requested to reset your MFA settings.
    
    Click the link below to disable MFA and regain access to your account:
    {reset_link}
    
    This link expires in 1 hour.
    
    If you did not request this, please ignore this email and your MFA settings will remain unchanged.
    
    IP Address: {request.remote_addr}
    Time: {datetime.utcnow().strftime('%Y-%m-%d %H:%M:%S UTC')}
    """
    
    send_email(user.email, 'MFA Reset Request', email_body)
    
    log_audit(user.id, 'MFA_RESET_REQUESTED', details=f'Token sent to {email}')
    
    return jsonify({'message': response_message}), 200

@app.route('/confirm-reset-mfa', methods=['GET', 'POST'])
def confirm_reset_mfa():
    if request.method == 'GET':
        token = request.args.get('token')
        if not token:
            return jsonify({'error': 'Token required'}), 400
        
        # Verify token exists and is valid
        reset_token = MFAResetToken.query.filter_by(token=token, used=False).first()
        
        if not reset_token or reset_token.expires_at < datetime.utcnow():
            return jsonify({'error': 'Invalid or expired reset token'}), 400
        
        # Return confirmation page
        return render_template_string('''
            <html>
            <body>
                <h2>Confirm MFA Reset</h2>
                <p>Are you sure you want to disable MFA for your account?</p>
                <form method="POST">
                    <input type="hidden" name="token" value="{{ token }}">
                    <button type="submit">Confirm Reset MFA</button>
                </form>
            </body>
            </html>
        ''', token=token)
    
    # POST request
    token = request.form.get('token') or request.get_json().get('token')
    
    if not token:
        return jsonify({'error': 'Token required'}), 400
    
    reset_token = MFAResetToken.query.filter_by(token=token, used=False).first()
    
    if not reset_token or reset_token.expires_at < datetime.utcnow():
        log_audit(None, 'MFA_RESET_FAILED', success=False, details='Invalid or expired token')
        return jsonify({'error': 'Invalid or expired reset token'}), 400
    
    user = User.query.get(reset_token.user_id)
    if not user:
        return jsonify({'error': 'User not found'}), 404
    
    # CRITICAL SECURITY CHECKS
    # 1. Verify the token hasn't been used
    if reset_token.used:
        log_audit(user.id, 'MFA_RESET_FAILED', success=False, details='Token already used')
        return jsonify({'error': 'Reset token already used'}), 400
    
    # 2. Mark token as used BEFORE disabling MFA
    reset_token.used = True
    db.session.commit()
    
    # 3. Disable MFA
    user.mfa_enabled = False
    user.mfa_secret = None
    db.session.commit()
    
    # 4. CRITICAL: Invalidate ALL existing sessions for this user
    Session.query.filter_by(user_id=user.id).delete()
    db.session.commit()
    
    log_audit(user.id, 'MFA_RESET_COMPLETED', details=f'IP: {request.remote_addr}')
    
    # Send notification email
    notification_body = f"""
    Your MFA has been disabled via the reset process.
    
    If you did not perform this action, your account may be compromised.
    Please change your password immediately and re-enable MFA.
    
    IP Address: {request.remote_addr}
    Time: {datetime.utcnow().strftime('%Y-%m-%d %H:%M:%S UTC')}
    """
    send_email(user.email, 'MFA Disabled - Security Alert', notification_body)
    
    return jsonify({
        'message': 'MFA has been disabled. Please log in with your password and consider re-enabling MFA.'
    }), 200

@app.route('/profile', methods=['GET'])
@require_auth(require_mfa=False)
def profile():
    user = request.current_user
    
    return jsonify({
        'email': user.email,
        'mfa_enabled': user.mfa_enabled,
        'mfa_verified': request.current_session.mfa_verified,
        'created_at': user.created_at.isoformat()
    }), 200

@app.route('/audit-logs', methods=['GET'])
@require_auth(require_mfa=False)
def audit_logs():
    user = request.current_user
    
    # CRITICAL: Require MFA verification to view audit logs
    if user.mfa_enabled and not request.current_session.mfa_verified:
        return jsonify({'error': 'MFA verification required'}), 403
    
    logs = AuditLog.query.filter_by(user_id=user.id).order_by(AuditLog.created_at.desc()).limit(50).all()
    
    return jsonify({
        'logs': [{
            'action': log.action,
            'success': log.success,
            'ip_address': log.ip_address,
            'created_at': log.created_at.isoformat(),
            'details': log.details
        } for log in logs]
    }), 200

